declare function useFormattedDate(date: Date | undefined, format?: string, zone?: string): string;

declare function useFormattedDateTime(date: Date | undefined, format?: string, zone?: string): string;

declare namespace EthiopianDate {
    const minEurDate: Date;
    const maxEurDate: Date;
    interface EtDate {
        Day: number;
        Month: number;
        Year: number;
    }
    interface EtDateTime extends EtDate {
        hours: number;
        minutes: number;
        seconds?: number;
    }
    const shortDays: string[];
    const longDays: string[];
    const ethMonths: string[];
    const ethMonthsLatin: string[];
    function isLeapYearEt(y: number): boolean;
    function ethiopianMonthLength(m: number, y: number): number;
    function toEth(gregorianDate: Date): EtDate;
    function toGreg(ethDate: EtDate): Date;
    function getEtMonthName(m: number, useAmharic?: boolean): string;
    function formatEtDate(date: EtDate, locale?: "AMH" | "EN"): string;
}

declare function useFormattedEthiopianDate(etDate: EthiopianDate.EtDate, format?: string): string;
declare function useFormattedEthiopianDateTime(etDateTime: EthiopianDate.EtDateTime, format?: string): string;

export { useFormattedDate, useFormattedDateTime, useFormattedEthiopianDate, useFormattedEthiopianDateTime };
